import React, { useState } from 'react';
import { useAuth } from '../context/AuthContext';
import axiosInstance from '../axiosConfig';

const TOPIC_COLOURS = {
  Tech: '#80B0E8',
  Culture: '#F29CC3',
  Science: '#D1CAEA',
  Gaming: '#D6D35F',
  Sports: '#C45F3F',
  Other: '#898E46',
};

const ThreadCard = ({ thread, onRefresh }) => {
  const { user } = useAuth();
  const [editing, setEditing] = useState(false);
  const [editForm, setEditForm] = useState({ title: thread.title, topic: thread.topic, content: thread.content });

  const handleDelete = async (threadId) => {
    try {
      await axiosInstance.delete(`/api/threads/${threadId}`, {
        headers: { Authorization: `Bearer ${user.token}` },
      });
      setThreads(threads.filter((thread) => thread._id !== threadId));
    } catch (error) {
      alert('Failed to delete thread.');
    }
  };

  const handleEdit = async (e) => {
    e.preventDefault();
    await axiosInstance.put(`/api/threads/${thread._id}`, editForm);
    setEditing(false);
    onRefresh();
  };

  const tagColour = TOPIC_COLOURS[thread.topic] || '#ccc';
  const isAuthor = user && user._id === thread.author._id;

  return (
    <div className="thread-card">
      <div className="thread-header">
        <div className="thread-avatar">
          {thread.author?.name?.charAt(0).toUpperCase() || '?'}
        </div>
        <div>
          <span className="thread-author">{thread.author?.name}</span>
          <span className="thread-time">{new Date(thread.createdAt).toLocaleString()}</span>
        </div>
      </div>

      {editing ? (
        <form onSubmit={handleEdit} className="edit-form">
          <input
            value={editForm.title}
            onChange={(e) => setEditForm({ ...editForm, title: e.target.value })}
          />
          <textarea
            value={editForm.content}
            onChange={(e) => setEditForm({ ...editForm, content: e.target.value })}
          />
          <button type="submit">Save</button>
          <button type="button" onClick={() => setEditing(false)}>Cancel</button>
        </form>
      ) : (
        <>
          <h3 className="thread-title">{thread.title}</h3>
          <p className="thread-content">{thread.content}</p>
          <span className="thread-topic" style={{ backgroundColor: TOPIC_COLOURS[thread.topic] || '#ccc' }}>
            {thread.topic}
          </span>
        </>
      )}

      <div className="thread-footer">
        <span className="topic-tag" style={{ background: TOPIC_COLOURS[thread.topic] || '#ccc' }}>
          {thread.topic}
        </span>
        <button>Comment</button>
        <button>Like</button>
        {isAuthor && (
          <>
            <button onClick={() => setEditing(true)}>Edit</button>
            <button onClick={() => handleDelete(thread._id)}>Delete</button>
          </>
        )}
      </div>
    </div>
  );
}

export default ThreadCard;
